import os
import sys
import time
import json
import base64
import ctypes
import ctypes.wintypes
import threading
import io
from datetime import datetime
from pathlib import Path
import tkinter as tk
from tkinter import filedialog, messagebox

try:
    import pystray
    from PIL import Image, ImageGrab
    import win32gui
    import win32con
    import win32api
except ImportError as e:
    print(f"必要なライブラリが不足しています: {e}")
    input("Enterキーで終了...")
    sys.exit(1)

ICON_B64 = ""

CONFIG_PATH = Path(os.environ.get("APPDATA", "")) / "CapDozo" / "config.json"
STARTUP_BAT = (
    Path(os.environ["APPDATA"])
    / "Microsoft" / "Windows" / "Start Menu" / "Programs" / "Startup"
    / "CapDozo.bat"
)

DEFAULT_CONFIG = {
    "save_dir": str(Path.home() / "OneDrive" / "デスクトップ"),
    "prefix": "screenshot",
    "seq_digits": 6,
    "seq_start": 0,
    "use_timestamp": True,
    "format": "jpg",
}

FORMAT_EXT = {
    "jpg": (".jpg", "JPEG"),
    "png": (".png", "PNG"),
    "bmp": (".bmp", "BMP"),
}


def load_config():
    if CONFIG_PATH.exists():
        try:
            with open(CONFIG_PATH, encoding="utf-8") as f:
                cfg = json.load(f)
                for k, v in DEFAULT_CONFIG.items():
                    cfg.setdefault(k, v)
                return cfg
        except Exception:
            pass
    return DEFAULT_CONFIG.copy()


def save_config(cfg):
    CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(CONFIG_PATH, "w", encoding="utf-8") as f:
        json.dump(cfg, f, ensure_ascii=False, indent=2)


config = load_config()


def get_save_path():
    save_dir = Path(config["save_dir"])
    save_dir.mkdir(parents=True, exist_ok=True)
    ext, _ = FORMAT_EXT[config.get("format", "jpg")]
    if config["use_timestamp"]:
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        return save_dir / f"{config['prefix']}_{ts}{ext}"
    else:
        seq = config.get("seq_current", config["seq_start"])
        digits = config["seq_digits"]
        path = save_dir / f"{config['prefix']}_{str(seq).zfill(digits)}{ext}"
        config["seq_current"] = seq + 1
        save_config(config)
        return path


def save_image(img):
    path = get_save_path()
    ext, fmt = FORMAT_EXT[config.get("format", "jpg")]
    if fmt == "JPEG":
        img.convert("RGB").save(path, fmt, quality=95)
    else:
        img.convert("RGB").save(path, fmt)
    return path


def enable_dpi_aware():
    try:
        ctypes.windll.shcore.SetProcessDpiAwareness(2)
    except Exception:
        try:
            ctypes.windll.user32.SetProcessDPIAware()
        except Exception:
            pass


def flash_screen():
    vx = win32api.GetSystemMetrics(win32con.SM_XVIRTUALSCREEN)
    vy = win32api.GetSystemMetrics(win32con.SM_YVIRTUALSCREEN)
    vw = win32api.GetSystemMetrics(win32con.SM_CXVIRTUALSCREEN)
    vh = win32api.GetSystemMetrics(win32con.SM_CYVIRTUALSCREEN)
    root = tk.Tk()
    root.overrideredirect(True)
    root.attributes("-topmost", True)
    root.attributes("-alpha", 0.4)
    root.configure(bg="black")
    root.geometry(f"{vw}x{vh}+{vx}+{vy}")
    root.after(120, root.destroy)
    root.mainloop()


def capture_fullscreen():
    left   = win32api.GetSystemMetrics(win32con.SM_XVIRTUALSCREEN)
    top    = win32api.GetSystemMetrics(win32con.SM_YVIRTUALSCREEN)
    width  = win32api.GetSystemMetrics(win32con.SM_CXVIRTUALSCREEN)
    height = win32api.GetSystemMetrics(win32con.SM_CYVIRTUALSCREEN)
    img = ImageGrab.grab(bbox=(left, top, left + width, top + height), all_screens=True)
    path = save_image(img)
    flash_screen()
    return path


def capture_selected_window():
    hwnd = win32gui.GetForegroundWindow()
    if not hwnd:
        return None
    rect = win32gui.GetWindowRect(hwnd)
    left, top, right, bottom = rect
    if right - left <= 0 or bottom - top <= 0:
        return None
    img = ImageGrab.grab(bbox=(left, top, right, bottom), all_screens=True)
    path = save_image(img)
    flash_screen()
    return path


class RectSelector:
    def __init__(self, on_selected):
        self.on_selected = on_selected
        self.start_x = 0
        self.start_y = 0
        self.rect_id = None

        self.vx = win32api.GetSystemMetrics(win32con.SM_XVIRTUALSCREEN)
        self.vy = win32api.GetSystemMetrics(win32con.SM_YVIRTUALSCREEN)
        self.vw = win32api.GetSystemMetrics(win32con.SM_CXVIRTUALSCREEN)
        self.vh = win32api.GetSystemMetrics(win32con.SM_CYVIRTUALSCREEN)

        self.root = tk.Tk()
        self.root.overrideredirect(True)
        self.root.attributes("-topmost", True)
        self.root.attributes("-alpha", 0.25)
        self.root.configure(bg="black")
        self.root.geometry(f"{self.vw}x{self.vh}+{self.vx}+{self.vy}")

        self.canvas = tk.Canvas(
            self.root,
            cursor="cross",
            bg="black",
            highlightthickness=0,
            width=self.vw,
            height=self.vh,
        )
        self.canvas.pack(fill=tk.BOTH, expand=True)

        self.canvas.bind("<ButtonPress-1>", self.on_press)
        self.canvas.bind("<B1-Motion>", self.on_drag)
        self.canvas.bind("<ButtonRelease-1>", self.on_release)
        self.root.bind("<Escape>", lambda e: self.cancel())

        self.root.mainloop()

    def on_press(self, event):
        self.start_x = self.root.winfo_pointerx()
        self.start_y = self.root.winfo_pointery()
        self.rect_id = self.canvas.create_rectangle(
            0, 0, 0, 0, outline="red", width=2, fill=""
        )

    def on_drag(self, event):
        cx = self.root.winfo_pointerx() - self.vx
        cy = self.root.winfo_pointery() - self.vy
        sx = self.start_x - self.vx
        sy = self.start_y - self.vy
        self.canvas.coords(self.rect_id, sx, sy, cx, cy)

    def on_release(self, event):
        end_x = self.root.winfo_pointerx()
        end_y = self.root.winfo_pointery()
        self.root.destroy()
        left   = min(self.start_x, end_x)
        top    = min(self.start_y, end_y)
        right  = max(self.start_x, end_x)
        bottom = max(self.start_y, end_y)
        if right - left > 5 and bottom - top > 5:
            self.on_selected(left, top, right, bottom)

    def cancel(self):
        self.root.destroy()


def capture_rect():
    def on_selected(left, top, right, bottom):
        img = ImageGrab.grab(bbox=(left, top, right, bottom), all_screens=True)
        save_image(img)
        flash_screen()
    RectSelector(on_selected)


def open_settings():
    win = tk.Tk()
    win.title("キャプどうぞ 設定")
    win.resizable(False, False)
    win.attributes("-topmost", True)

    px, py = 14, 8

    def g(row, col, **kw):
        return {"row": row, "column": col, "padx": px, "pady": py, **kw}

    tk.Label(win, text="保存先フォルダ:").grid(**g(0, 0, sticky="w"))
    save_dir_var = tk.StringVar(value=config["save_dir"])
    tk.Entry(win, textvariable=save_dir_var, width=42).grid(**g(0, 1, sticky="ew"))

    def browse():
        win.update()
        d = filedialog.askdirectory(parent=win, initialdir=save_dir_var.get())
        if d:
            save_dir_var.set(d)
        win.lift()
        win.focus_force()

    tk.Button(win, text="  参照  ", command=browse).grid(**g(0, 2))

    tk.Label(win, text="接頭語:").grid(**g(1, 0, sticky="w"))
    prefix_var = tk.StringVar(value=config["prefix"])
    tk.Entry(win, textvariable=prefix_var, width=22).grid(**g(1, 1, sticky="w"))

    tk.Label(win, text="出力形式:").grid(**g(2, 0, sticky="w"))
    format_var = tk.StringVar(value=config.get("format", "jpg"))
    fmt_frame = tk.Frame(win)
    fmt_frame.grid(**g(2, 1, sticky="w"))
    for fmt in ["jpg", "png", "bmp"]:
        tk.Radiobutton(
            fmt_frame, text=f"  {fmt.upper()}  ",
            variable=format_var, value=fmt,
            indicatoron=True, padx=8, pady=6
        ).pack(side="left", padx=4)

    use_ts_var = tk.BooleanVar(value=config["use_timestamp"])
    tk.Checkbutton(
        win, text="タイムスタンプを使う（OFFで連番）",
        variable=use_ts_var, padx=6, pady=6
    ).grid(**g(3, 0, columnspan=2, sticky="w"))

    tk.Label(win, text="連番桁数:").grid(**g(4, 0, sticky="w"))
    digits_var = tk.IntVar(value=config["seq_digits"])
    tk.Spinbox(win, from_=1, to=10, textvariable=digits_var, width=6).grid(**g(4, 1, sticky="w"))

    tk.Label(win, text="連番開始番号:").grid(**g(5, 0, sticky="w"))
    seq_var = tk.IntVar(value=config["seq_start"])
    tk.Spinbox(win, from_=0, to=99999, textvariable=seq_var, width=9).grid(**g(5, 1, sticky="w"))

    btn_frame = tk.Frame(win)
    btn_frame.grid(row=6, column=0, columnspan=3, pady=12)

    def on_ok():
        config["save_dir"]      = save_dir_var.get()
        config["prefix"]        = prefix_var.get()
        config["format"]        = format_var.get()
        config["use_timestamp"] = use_ts_var.get()
        config["seq_digits"]    = digits_var.get()
        config["seq_start"]     = seq_var.get()
        config["seq_current"]   = seq_var.get()
        save_config(config)
        win.destroy()

    tk.Button(btn_frame, text="     OK     ", command=on_ok).pack(side="left", padx=12)
    tk.Button(btn_frame, text=" キャンセル ", command=win.destroy).pack(side="left", padx=12)

    win.mainloop()


def get_exe_path():
    if getattr(sys, "frozen", False):
        return Path(sys.executable)
    return Path(sys.argv[0]).resolve()


def is_startup_registered():
    return STARTUP_BAT.exists()


def register_startup():
    exe_path = get_exe_path()
    bat_content = f'@echo off\nstart "" "{exe_path}"\n'
    STARTUP_BAT.write_text(bat_content, encoding="utf-8")
    messagebox.showinfo("スタートアップ登録", "スタートアップに登録しました。")


def unregister_startup():
    if STARTUP_BAT.exists():
        STARTUP_BAT.unlink()
    messagebox.showinfo("スタートアップ解除", "スタートアップから解除しました。")


def toggle_startup(icon, item):
    def _toggle():
        if is_startup_registered():
            unregister_startup()
        else:
            register_startup()
        icon.update_menu()
    threading.Thread(target=_toggle, daemon=True).start()





def create_icon_image():
    try:
        img_data = base64.b64decode(ICON_B64)
        img = Image.open(io.BytesIO(img_data)).resize((64, 64), Image.LANCZOS).convert("RGBA")
        return img
    except Exception:
        return Image.new("RGBA", (64, 64), (255, 0, 0, 255))


def main():
    mutex = ctypes.windll.kernel32.CreateMutexW(None, False, "CapDozoMutex")
    if ctypes.windll.kernel32.GetLastError() == 183:
        sys.exit(0)

    enable_dpi_aware()

    icon_image = create_icon_image()

    def do_fullscreen(icon, item):
        time.sleep(0.5)
        capture_fullscreen()

    def do_selected_window(icon, item):
        time.sleep(2.0)
        capture_selected_window()

    def do_rect(icon, item):
        capture_rect()

    def do_open_folder(icon, item):
        os.startfile(config["save_dir"])

    def do_settings(icon, item):
        threading.Thread(target=open_settings, daemon=True).start()

    def startup_label(item):
        return "✅ スタートアップ登録済み" if is_startup_registered() else "🔁 スタートアップに登録"

    menu = pystray.Menu(
        pystray.MenuItem("⚙️  設定",                  do_settings),
        pystray.Menu.SEPARATOR,
        pystray.MenuItem("📸 フルスクリーン",        do_fullscreen),
        pystray.MenuItem("🪟 ウィンドウを選択",       do_selected_window),
        pystray.MenuItem("✂️  矩形選択",              do_rect),
        pystray.Menu.SEPARATOR,
        pystray.MenuItem("📁 保存フォルダを開く",     do_open_folder),
        pystray.Menu.SEPARATOR,
        pystray.MenuItem(startup_label,              toggle_startup),
        pystray.Menu.SEPARATOR,
        pystray.MenuItem("❌ 終了",                  lambda icon, item: (icon.stop(), sys.exit(0))),
    )

    icon = pystray.Icon(
        "capdozo",
        icon_image,
        "キャプどうぞ",
        menu,
    )
    icon.run()


if __name__ == "__main__":
    main()
